-- ============================================================================
-- Add a spicy, contrarian third smaczek to the whole catalog (2026-07-09)
-- ----------------------------------------------------------------------------
-- Product decision: give every question a third discussion angle in the
-- 'ostro i pod wlos' register (sharp, against-the-grain, turns the blade on
-- the reader). Position 3 is PRO-gated automatically by get_question_smaczki
-- (is_locked = not (premium or position=1)); the UI renders smaczki
-- dynamically, so no app change is needed. 992 new position-3 smaczki (the
-- 8 questions that already had a third are left untouched via ON CONFLICT).
-- Also backfills position 2 for the 3 questions that only had position 1.
--
-- Idempotent: unique (question_id, position) + ON CONFLICT DO NOTHING means a
-- re-run is a no-op and translations are only inserted for newly-created rows.
-- Full PL+EN text of every addition is in the sibling .backup.json.
-- ============================================================================

begin;

-- Backfill position 2 (3 questions)
with data(qid, pl, en) as (
  values
    ('bb9cd554-c2e7-4ac5-a8d2-4170af1c1ed5'::uuid,'Zawsze włączone znaczy zawsze wygodne','Always-on means always convenient'),
    ('d14f8d93-51a9-4205-b33d-4d934704ad11'::uuid,'Nazwij to inaczej: gapienie się','Call it what it is: staring'),
    ('db263ba8-84f4-4bdf-b369-2e7249924bad'::uuid,'Trzech to po prostu trzech przyjaciół','Three is just three friends')
),
ins as (
  insert into public.question_smaczki (question_id, position, is_active)
  select qid, 2, true from data
  on conflict (question_id, position) do nothing
  returning id, question_id
)
insert into public.question_smaczki_translations (smaczek_id, locale, text)
select ins.id, x.locale, x.text
from ins
join data d on d.qid = ins.question_id
cross join lateral (values ('pl', d.pl), ('en', d.en)) as x(locale, text);

