ins as (
  insert into public.question_smaczki (question_id, position, is_active)
  select qid, 3, true from data
  on conflict (question_id, position) do nothing
  returning id, question_id
)
insert into public.question_smaczki_translations (smaczek_id, locale, text)
select ins.id, x.locale, x.text
from ins
join data d on d.qid = ins.question_id
cross join lateral (values ('pl', d.pl), ('en', d.en)) as x(locale, text);

commit;
